VALUES
  ('heelevel3-6e2f88c7-moex-00222', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列關於買回之敘述，何者正確？', '["買回之期限不得超過5年，超過5年者，買回之約定無效", "買回之價金，當事人得以特約定之", "買回之費用，原則上由買受人與買回人共同負擔", "買受人因可歸責於自己之事由，致不能交付標的物時，買回之約定失效 32620、33320"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00223', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲與乙約定，乙為甲服勞務自110年1月1日起1年，而甲給付報酬。下列敘述，何者錯誤？', '["若甲受領勞務遲延，乙無補服勞務之義務，仍得請求報酬", "甲非經乙同意，不得將其勞務請求權讓與第三人", "乙非經甲同意，不得使第三人代服勞務", "乙得隨時終止契約，但有利於甲之習慣者，從其習慣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00224', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列關於合夥人責任之敘述，何者正確？', '["民法第681條規定，合夥人對於合夥債務，連帶負其責任，故債權人得選擇先向合夥人個人單 獨所有之財產求償。若有不足之額，再向合夥財產求償", "民法第681條，就合夥人就合夥對外所負之責任，採取併存主義", "依民法規定合夥債務，原則上為各合夥人之公同共有債務", "民法第681條所稱之連帶，係指合夥人與合夥財產之連帶關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00225', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列關於承攬法定抵押權之敘述，何者錯誤？', '["法定抵押權之設定，係為擔保承攬關係報酬額", "承攬契約以書面定之者，關於法定抵押權之登記，承攬人得單獨申請之", "法定抵押權之標的，限於工作所附定作人所有之不動產", "承攬人得於工作開始前，請求預為抵押權登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00226', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲有一宗A地，為二重買賣，先與乙訂立買賣契約，並將A地交付於乙；後與丙訂立買賣契約， 並將A地之所有權移轉登記於丙。關於甲、乙、丙三人間之法律關係，下列敘述，何者正確？', '["丙得請求乙返還A地之占有", "甲得請求乙返還A地之占有", "乙得請求丙移轉A地所有權", "甲得請求丙返還A地所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00227', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲、乙二人向丙、丁二人承租基地建築二層樓A屋，甲、乙分別共有A屋，丙、丁分別共有A屋 座落之基地。下列共有物，何者並非因物之使用目的而不能分割？', '["A屋座落之基地", "A屋之太平梯", "A屋之亭子腳", "A屋之共有車道"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00228', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列何者，非為不動產物權依法律行為而得喪變更時之要件？', '["物權變動之合意", "書面", "交付", "登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00229', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列關於解除權與撤銷權之敘述，何者正確？', '["二者均屬形成權", "二者均適用於一切法律行為", "前者限於法律所規定；後者則包含約定與法定", "原則上二者均不溯及既往"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00230', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲之女乙嫁於丙為妻，甲與丙之父丁在法律上係何種關係？', '["姻親關係", "旁系血親關係", "直系血親關係", "無任何關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00231', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲乙為適用法定財產制之配偶。甲為減少乙將來對於剩餘財產之分配，而於 2018 年將時價新臺 幣（下同）2000 萬元婚後財產 A 屋，贈與並移轉 A 屋所有權於知情之丙。甲乙於 2022 年離婚 時，甲有婚後財產時價800萬元，乙有婚後財產時價1100萬元，丙所有之A屋價值2200萬元。 下列敘述，何者正確？', '["甲乙雙方婚後剩餘財產差額為300萬元", "甲得向乙請求分配150萬元", "甲乙雙方婚後剩餘財產差額為1900萬元", "乙得向丙請求返還50萬元 32620、33320"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL)
